// backend/src/routes/discovery/index.ts

import { Router } from 'express';
import { Pool } from 'pg';
import { logger } from '../../utils/logger';
import { authenticate } from '../../middleware/auth';

export const createDiscoveryRouter = (pool: Pool) => {
  const router = Router();

  router.get('/feed', authenticate(pool), async (req, res) => {
    const client = await pool.connect();
    try {
      const userId = req.user?.id;

      if (!userId) {
        res.status(401).json({ error: 'User not authenticated' });
        return;
      }

      // Get discovery preferences with fallback to defaults
      const prefsResult = await client.query(`
        INSERT INTO discovery_preferences (
          user_id, 
          min_viewers, 
          max_viewers, 
          preferred_languages,
          content_rating, 
          notify_only, 
          schedule_match, 
          confidence_threshold
        )
        VALUES ($1, 100, 50000, ARRAY['en'], 'all', false, true, 0.7)
        ON CONFLICT (user_id) DO UPDATE SET
          updated_at = CURRENT_TIMESTAMP
        RETURNING *
      `, [userId]);

      const preferences = prefsResult.rows[0];

      // Get premieres
      const premieresResult = await client.query(`
        SELECT 
          pe.*,
          c.username, c.display_name, c.profile_image_url,
          g.name as game_name, g.box_art_url
        FROM premiere_events pe
        JOIN channels c ON pe.channel_id = c.id
        JOIN games g ON pe.current_game_id = g.id
        WHERE pe.start_time > NOW()
        AND EXISTS (
          SELECT 1 FROM user_channel_preferences ucp 
          WHERE ucp.user_id = $1 
          AND ucp.channel_id = pe.channel_id
        )
        ORDER BY pe.start_time ASC
        LIMIT 10
      `, [userId]);

      // Get rising channels
      const risingChannelsResult = await client.query(`
        WITH channel_metrics AS (
          SELECT 
            channel_id,
            AVG(viewer_count) as avg_viewers,
            AVG(COALESCE(viewer_growth_rate, 0)) as growth_rate
          FROM channel_metrics
          WHERE recorded_at > NOW() - INTERVAL '7 days'
          GROUP BY channel_id
        )
        SELECT 
          c.*,
          COALESCE(cm.avg_viewers, 0) as avg_viewers,
          COALESCE(cm.growth_rate, 0) as growth_rate,
          g.name as current_game_name,
          g.box_art_url as game_image,
          COUNT(DISTINCT v.id) as recorded_vods
        FROM channels c
        LEFT JOIN channel_metrics cm ON c.id = cm.channel_id
        LEFT JOIN games g ON c.current_game_id = g.id
        LEFT JOIN vods v ON c.id = v.channel_id 
          AND v.download_status = 'completed'
          AND v.user_id = $1
        WHERE COALESCE(cm.growth_rate, 0) > 0.1
        AND COALESCE(cm.avg_viewers, 0) BETWEEN $2 AND $3
        AND c.is_active = true
        GROUP BY 
          c.id, 
          cm.avg_viewers, 
          cm.growth_rate, 
          g.name, 
          g.box_art_url
        ORDER BY cm.growth_rate DESC NULLS LAST
        LIMIT 5
      `, [userId, preferences.min_viewers, preferences.max_viewers]);

      // Get recommendations
      const recommendationsResult = await client.query(`
        WITH channel_history AS (
          SELECT 
            c.id as channel_id, 
            COUNT(DISTINCT v.current_game_id) as games_in_common,
            MAX(CASE WHEN v.download_status = 'completed' THEN 1 ELSE 0 END) as has_downloads
          FROM channels c
          JOIN vods v ON c.id = v.channel_id
          WHERE v.current_game_id IN (
            SELECT DISTINCT current_game_id 
            FROM vods 
            WHERE user_id = $1
            AND current_game_id IS NOT NULL
          )
          AND c.is_active = true 
          GROUP BY c.id
        )
        SELECT 
          c.*,
          ch.games_in_common,
          COALESCE(cm.viewer_count, 0) as current_viewers
        FROM channels c
        JOIN channel_history ch ON c.id = ch.channel_id
        LEFT JOIN channel_metrics cm ON c.id = cm.channel_id
        WHERE ch.games_in_common >= 3
        AND NOT EXISTS (
          SELECT 1 
          FROM user_channel_preferences ucp 
          WHERE ucp.user_id = $1 
          AND ucp.channel_id = c.id
        )
        ORDER BY ch.games_in_common DESC, cm.viewer_count DESC NULLS LAST
        LIMIT 5
      `, [userId]);

      res.json({
        preferences,
        premieres: premieresResult.rows,
        risingChannels: risingChannelsResult.rows,
        recommendations: {
          channels: recommendationsResult.rows
        }
      });

    } catch (error) {
      logger.error('Error fetching discovery feed:', error);
      res.status(500).json({ error: 'Failed to fetch discovery feed' });
    } finally {
      client.release();
    }
  });

  // Update discovery preferences route remains unchanged
  router.put('/preferences', authenticate(pool), async (req, res) => {
    const client = await pool.connect();
    try {
      const userId = req.user?.id;

      if (!userId) {
        res.status(401).json({ error: 'User not authenticated' });
        return;
      }

      const {
        min_viewers,
        max_viewers,
        preferred_languages,
        content_rating,
        notify_only,
        schedule_match,
        confidence_threshold
      } = req.body;

      const result = await client.query(`
        UPDATE discovery_preferences
        SET 
          min_viewers = $2,
          max_viewers = $3,
          preferred_languages = $4,
          content_rating = $5,
          notify_only = $6,
          schedule_match = $7,
          confidence_threshold = $8,
          updated_at = CURRENT_TIMESTAMP
        WHERE user_id = $1
        RETURNING *
      `, [
        userId,
        min_viewers,
        max_viewers,
        preferred_languages,
        content_rating,
        notify_only,
        schedule_match,
        confidence_threshold
      ]);

      res.json(result.rows[0]);
    } catch (error) {
      logger.error('Error updating discovery preferences:', error);
      res.status(500).json({ error: 'Failed to update discovery preferences' });
    } finally {
      client.release();
    }
  });

  return router;
};

export default createDiscoveryRouter;

